import { ensureSchema } from "./schema.mjs";

export async function createShipment(db, data) {
  await ensureSchema(db);
  const result = await db.collection("shipments").insertOne(data);
  return { _id: result.insertedId, ...data };
}

export async function getShipment(db, shipmentId) {
  return db.collection("shipments").findOne({ shipmentId });
}

export async function getShipmentsByOrder(db, orderId) {
  return db.collection("shipments").find({ orderId }).toArray();
}

